class KStacks:
    def __init__(self, num_stacks, capacity):
        self.num_stacks = num_stacks
        self.capacity = capacity
        self.arr = [0] * self.capacity
        self.top = [-1] * self.num_stacks
        self.next_idx = [0] * self.capacity

        for i in range(self.capacity - 1):
            self.next_idx[i] = i + 1
        self.next_idx[self.capacity - 1] = -1

        self.free_list_head = 0

    def _check_stack_num(self, stack_num):
        if not (0 <= stack_num < self.num_stacks):
            raise ValueError(f"Stack number must be between 0 and {self.num_stacks - 1}")

    def is_empty(self, stack_num):
        self._check_stack_num(stack_num)
        return self.top[stack_num] == -1

    def is_full(self):
        return self.free_list_head == -1

    def push(self, item, stack_num):
        self._check_stack_num(stack_num)

        if self.is_full():
            raise OverflowError("Stack array is full!")

        current_free_idx = self.free_list_head
        self.free_list_head = self.next_idx[current_free_idx]
        self.arr[current_free_idx] = item
        self.next_idx[current_free_idx] = self.top[stack_num]
        self.top[stack_num] = current_free_idx

    def pop(self, stack_num):
        self._check_stack_num(stack_num)

        if self.is_empty(stack_num):
            raise IndexError(f"Stack {stack_num} is empty!")

        current_top_idx = self.top[stack_num]
        item = self.arr[current_top_idx]
        self.top[stack_num] = self.next_idx[current_top_idx]
        self.next_idx[current_top_idx] = self.free_list_head
        self.free_list_head = current_top_idx

        return item

    def peek(self, stack_num):
        self._check_stack_num(stack_num)
        if self.is_empty(stack_num):
            raise IndexError(f"Stack {stack_num} is empty!")
        return self.arr[self.top[stack_num]]
